import React from 'react';
import { Image, SafeAreaView, StyleSheet, Text, TouchableOpacity, View } from 'react-native';
import { StatusBar } from 'expo-status-bar';

export default function App() {
  return (
    <SafeAreaView style={styles.container}>
      <StatusBar style="dark" />

      <View style={styles.topSection}>
        <View style={styles.logoWrapper}>
          <View style={styles.logoCircle}>
            <Image source={require('./assets/logo.png')} style={styles.logo} resizeMode="contain" />
          </View>
          <Text style={styles.brandTitle}>zoovita</Text>
          <Text style={styles.brandSubtitle}>Barcha hayvonlar uchun</Text>
          <Text style={styles.brandHighlight}>hammasi bir joyda</Text>
        </View>
      </View>

      <View style={styles.bottomCard}>
        <View style={styles.pagination}>
          <View style={[styles.dot, styles.dotActive]} />
          <View style={styles.dot} />
          <View style={styles.dot} />
          <View style={styles.dot} />
        </View>
        <TouchableOpacity style={styles.button} activeOpacity={0.85}>
          <Text style={styles.buttonText}>Boshlash</Text>
          <Text style={styles.buttonArrow}>›</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F7FBF4',
  },
  topSection: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    paddingHorizontal: 24,
  },
  logoWrapper: {
    width: '100%',
    alignItems: 'center',
  },
  logoCircle: {
    width: 200,
    height: 200,
    borderRadius: 120,
    backgroundColor: '#ffffff',
    justifyContent: 'center',
    alignItems: 'center',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.08,
    shadowRadius: 16,
    elevation: 6,
  },
  logo: {
    width: 138,
    height: 138,
  },
  brandTitle: {
    marginTop: 32,
    fontSize: 36,
    fontWeight: '800',
    color: '#1A3A1C',
    textTransform: 'lowercase',
  },
  brandSubtitle: {
    marginTop: 12,
    fontSize: 16,
    color: '#3E5A3B',
  },
  brandHighlight: {
    marginTop: 6,
    fontSize: 18,
    fontWeight: '700',
    color: '#3C8E2D',
  },
  bottomCard: {
    paddingHorizontal: 24,
    paddingTop: 28,
    paddingBottom: 32,
    backgroundColor: '#ffffff',
    borderTopLeftRadius: 32,
    borderTopRightRadius: 32,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: -4 },
    shadowOpacity: 0.08,
    shadowRadius: 16,
    elevation: 10,
  },
  pagination: {
    flexDirection: 'row',
    justifyContent: 'center',
    gap: 10,
    marginBottom: 28,
  },
  dot: {
    width: 10,
    height: 10,
    borderRadius: 6,
    backgroundColor: '#D9E8D1',
  },
  dotActive: {
    width: 24,
    backgroundColor: '#3C8E2D',
  },
  button: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#2F7A29',
    paddingVertical: 18,
    borderRadius: 18,
  },
  buttonText: {
    color: '#ffffff',
    fontSize: 18,
    fontWeight: '700',
  },
  buttonArrow: {
    color: '#ffffff',
    fontSize: 22,
    marginLeft: 12,
  },
});
